// FILE: apps/backend/agents/donchian-breakout/blueprint.ts
/**
 * Donchian Channel Breakout blueprint.
 *
 * Dimensions: timeframe × channelLength × atrMultiple × rewardRatio × leverage
 * = 2 TF × 3 channel × 3 ATR × 3 RR × 2 lev = 108 agents
 *
 * Factory logic lives in factory.ts (also used by batch runners).
 */
import type { AgentBlueprint, Dimension } from '../../src/core/agent/types.ts';
import { createDonchian } from './factory.ts';

type DonchianDim = Dimension & {
  timeframe: string;
  channelLength: number;
  atrMultiple: number;
  rewardRatio: number;
  leverage: number;
};

const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h'] as const;
const CHANNEL_LENGTHS = [20, 50, 100];
const ATR_MULTIPLES = [1.0, 2.0, 3.0];
const REWARD_RATIOS = [1.5, 2.0, 3.0];
const LEVERAGES = [20, 200] as const;

const dimensions: DonchianDim[] = [];

for (const lev of LEVERAGES) {
  for (const tf of TIMEFRAMES) {
    for (const ch of CHANNEL_LENGTHS) {
      for (const atr of ATR_MULTIPLES) {
        for (const rr of REWARD_RATIOS) {
          dimensions.push({
            id: `${tf}-ch${ch}-atr${atr}-rr${rr}-lev${lev}`,
            timeframe: tf,
            channelLength: ch,
            atrMultiple: atr,
            rewardRatio: rr,
            leverage: lev,
          });
        }
      }
    }
  }
}

export default {
  name: 'Donchian Breakout',
  version: '1.0.0',
  instrument: 'US100',
  dimensions,
  createAgent(dim: DonchianDim) {
    return createDonchian({
      name: `Donchian ${dim.timeframe} ch${dim.channelLength} atr${dim.atrMultiple} rr${dim.rewardRatio} lev${dim.leverage}`,
      timeframe: dim.timeframe as any,
      channelLength: dim.channelLength,
      atrMultiple: dim.atrMultiple,
      rewardRatio: dim.rewardRatio,
      leverage: dim.leverage,
    });
  },
} satisfies AgentBlueprint<any>;


// FILE: apps/backend/agents/donchian-breakout/factory.ts
/**
 * Donchian Channel Breakout agent factory.
 *
 * BUY when price breaks above the N-period high.
 * SELL (short) when price breaks below the N-period low.
 * Stop-loss at K × ATR from entry. Take-profit at R × stop distance.
 * One position at a time.
 *
 * Position sizing: risks a fixed % of equity per trade, computed from
 * the ATR-based stop distance. This makes size adaptive to volatility
 * and account equity.
 */
import type {
  Agent,
  AgentConfig,
  AgentResult,
  Candle,
  Context,
  Fill,
  Timeframe,
} from '../../src/core/agent/types.ts';

export interface DonchianParams {
  name: string;
  timeframe: Timeframe;
  channelLength: number;  // N — lookback for Donchian channel
  atrMultiple: number;    // K — SL = K × ATR
  rewardRatio: number;    // R — TP = R × SL distance
  leverage: number;
  riskPct?: number;       // fraction of equity to risk per trade (default 0.02)
}

interface DonchianState {
  candleCount: number;
}

const ATR_PERIOD = 14;

export function createDonchian(params: DonchianParams): Agent<DonchianState> {
  const { timeframe, channelLength, atrMultiple, rewardRatio } = params;
  const riskPct = params.riskPct ?? 0.02;

  // Warmup: need channelLength candles for the channel + ATR_PERIOD for ATR
  const warmupCandles = Math.max(channelLength, ATR_PERIOD) + 1;

  const config: AgentConfig = {
    name: params.name,
    version: '1.0.0',
    instrument: 'US100',
    primaryFeed: timeframe,
    leverage: params.leverage,
  };

  function init(): DonchianState {
    return { candleCount: 0 };
  }

  function computeATR(history: Candle[]): number {
    // Wilder's ATR from the last ATR_PERIOD+1 candles in history
    const start = Math.max(0, history.length - ATR_PERIOD - 1);
    const slice = history.slice(start);

    let atr = 0;
    let count = 0;
    let prevClose = slice[0]?.close ?? 0;

    for (let i = 1; i < slice.length; i++) {
      const c = slice[i];
      const tr = Math.max(
        c.high - c.low,
        Math.abs(c.high - prevClose),
        Math.abs(c.low - prevClose),
      );
      prevClose = c.close;

      count++;
      if (count <= ATR_PERIOD) {
        atr += tr;
        if (count === ATR_PERIOD) atr /= ATR_PERIOD;
      } else {
        atr = (atr * (ATR_PERIOD - 1) + tr) / ATR_PERIOD;
      }
    }

    return atr;
  }

  function onCandle(
    candle: Candle,
    ctx: Context,
    state: DonchianState,
  ): AgentResult<DonchianState> {
    const newState: DonchianState = { candleCount: state.candleCount + 1 };

    if (newState.candleCount < warmupCandles) {
      return { order: null, state: newState };
    }

    // Already in a position — let SL/TP handle the exit
    if (ctx.position) {
      return { order: null, state: newState };
    }

    const history = ctx.history;

    // Donchian channel: highest high and lowest low of the previous N candles
    // (excluding the current candle which is the last element in history)
    const lookbackStart = Math.max(0, history.length - channelLength - 1);
    const lookbackEnd = history.length - 1;
    let channelHigh = -Infinity;
    let channelLow = Infinity;
    for (let i = lookbackStart; i < lookbackEnd; i++) {
      const c = history[i];
      if (c.high > channelHigh) channelHigh = c.high;
      if (c.low < channelLow) channelLow = c.low;
    }

    // ATR for stop sizing
    const atr = computeATR(history);
    if (atr <= 0) return { order: null, state: newState };

    const slDistance = atrMultiple * atr;
    const tpDistance = rewardRatio * slDistance;

    // Position size: risk riskPct of available equity
    const equity = ctx.account.equity;
    const riskAmount = equity * riskPct;
    const lotSize = ctx.instrument.lotSize;
    let size = riskAmount / (slDistance * lotSize);

    // Clamp to instrument limits
    size = Math.max(ctx.instrument.minSize, size);
    size = Math.min(ctx.instrument.maxSize, size);

    // Breakout above channel → BUY
    if (candle.high > channelHigh) {
      return {
        order: {
          action: 'OPEN',
          side: 'BUY',
          size,
          stopLoss: candle.close - slDistance,
          takeProfit: candle.close + tpDistance,
        },
        state: newState,
      };
    }

    // Breakout below channel → SELL
    if (candle.low < channelLow) {
      return {
        order: {
          action: 'OPEN',
          side: 'SELL',
          size,
          stopLoss: candle.close + slDistance,
          takeProfit: candle.close - tpDistance,
        },
        state: newState,
      };
    }

    return { order: null, state: newState };
  }

  function onFill(_fill: Fill, state: DonchianState): DonchianState {
    return state;
  }

  return { config, init, onCandle, onFill };
}


// FILE: apps/backend/agents/example/blueprint.ts
/**
 * Example blueprint: EMA Crossover
 *
 * Demonstrates the contract with default params × timeframe × leverage.
 * The strategy logic is self-contained (no external factory).
 */
import type {
  Agent,
  AgentBlueprint,
  AgentConfig,
  Candle,
  Context,
  AgentResult,
  Dimension,
  Fill,
  Timeframe,
} from '../../src/core/agent/types.ts';

type ExampleDim = Dimension & {
  timeframe: string;
  leverage: number;
};

interface EmaState {
  fastEma: number;
  slowEma: number;
  prevFastAboveSlow: boolean;
  candleCount: number;
}

const FAST_PERIOD = 10;
const SLOW_PERIOD = 30;
const STOP_LOSS_PCT = 0.01;
const POSITION_SIZE = 0.5;
const WARMUP_CANDLES = 30;
const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h'] as const;
const LEVERAGES = [20, 200] as const;

function updateEma(prev: number, price: number, period: number): number {
  if (prev === 0) return price;
  const k = 2 / (period + 1);
  return price * k + prev * (1 - k);
}

function createEmaAgent(timeframe: Timeframe, leverage: number): Agent<EmaState> {
  const config: AgentConfig = {
    name: `EMA Crossover ${timeframe} lev${leverage}`,
    version: '1.0.0',
    instrument: 'US100',
    primaryFeed: timeframe,
    maxDrawdown: 0.15,
    leverage,
  };

  function init(): EmaState {
    return { fastEma: 0, slowEma: 0, prevFastAboveSlow: false, candleCount: 0 };
  }

  function onCandle(candle: Candle, ctx: Context, state: EmaState): AgentResult<EmaState> {
    const fastEma = updateEma(state.fastEma, candle.close, FAST_PERIOD);
    const slowEma = updateEma(state.slowEma, candle.close, SLOW_PERIOD);
    const fastAboveSlow = fastEma > slowEma;
    const candleCount = state.candleCount + 1;

    const newState: EmaState = { fastEma, slowEma, prevFastAboveSlow: fastAboveSlow, candleCount };

    if (candleCount < WARMUP_CANDLES) {
      return { order: null, state: newState };
    }

    if (fastAboveSlow && !state.prevFastAboveSlow && !ctx.position) {
      return {
        order: {
          action: 'OPEN',
          side: 'BUY',
          size: POSITION_SIZE,
          stopLoss: candle.close * (1 - STOP_LOSS_PCT),
        },
        state: newState,
      };
    }

    if (!fastAboveSlow && state.prevFastAboveSlow && ctx.position) {
      return { order: { action: 'CLOSE' }, state: newState };
    }

    return { order: null, state: newState };
  }

  function onFill(_fill: Fill, state: EmaState): EmaState {
    return state;
  }

  return { config, init, onCandle, onFill };
}

const dimensions: ExampleDim[] = [];

for (const lev of LEVERAGES) {
  for (const tf of TIMEFRAMES) {
    dimensions.push({
      id: `${tf}-lev${lev}`,
      timeframe: tf,
      leverage: lev,
    });
  }
}

export default {
  name: 'EMA Crossover',
  version: '1.0.0',
  instrument: 'US100',
  dimensions,
  createAgent(dim: ExampleDim) {
    return createEmaAgent(dim.timeframe as Timeframe, dim.leverage);
  },
} satisfies AgentBlueprint<EmaState>;


// FILE: apps/backend/agents/macd-ema/blueprint.ts
/**
 * MACD + EMA Trend Filter blueprint.
 *
 * Dimensions: timeframe × emaPeriod × tpReturn × leverage
 * = 2 TF × 3 EMA × 5 TP × 2 lev = 60 agents
 *
 * Factory logic lives in factory.ts (also used by batch runners).
 */
import type { AgentBlueprint, Dimension } from '../../src/core/agent/types.ts';
import { createMacdEmaAgent } from './factory.ts';

type MacdDim = Dimension & {
  timeframe: string;
  emaPeriod: number;
  tpReturn: number;
  leverage: number;
};

const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h'] as const;
const EMA_PERIODS = [50, 100, 200];
const TP_RETURNS = [0.10, 0.20, 0.30, 0.40, 0.50];
const LEVERAGES = [20, 200] as const;

const dimensions: MacdDim[] = [];

for (const lev of LEVERAGES) {
  for (const tf of TIMEFRAMES) {
    for (const ema of EMA_PERIODS) {
      for (const tp of TP_RETURNS) {
        const tpLabel = (tp * 100).toFixed(0);
        dimensions.push({
          id: `${tf}-ema${ema}-tp${tpLabel}-lev${lev}`,
          timeframe: tf,
          emaPeriod: ema,
          tpReturn: tp,
          leverage: lev,
        });
      }
    }
  }
}

export default {
  name: 'MACD + EMA',
  version: '1.0.0',
  instrument: 'US100',
  dimensions,
  createAgent(dim: MacdDim) {
    return createMacdEmaAgent({
      name: `MACD-EMA${dim.emaPeriod} ${dim.timeframe} tp${(dim.tpReturn * 100).toFixed(0)}% lev${dim.leverage}`,
      timeframe: dim.timeframe as any,
      emaPeriod: dim.emaPeriod,
      tpReturn: dim.tpReturn,
      leverage: dim.leverage,
    });
  },
} satisfies AgentBlueprint<any>;


// FILE: apps/backend/agents/macd-ema/factory.ts
/**
 * MACD + EMA trend filter agent.
 *
 * Strategy:
 *   - EMA(N) determines trend direction (price above = UP, below = DOWN)
 *   - MACD crossover triggers entry, only in direction of EMA trend
 *   - UP trend + bullish MACD cross → BUY
 *   - DOWN trend + bearish MACD cross → SELL
 *   - SL configurable (max -50% = platform constraint)
 *   - TP configurable
 *   - Reopens same direction after forced day-end close
 */

import type {
  Agent,
  AgentConfig,
  Candle,
  Context,
  AgentResult,
  Fill,
  Timeframe,
} from '../../src/core/agent/types.ts';
import { EMA, MACD } from '../../src/core/indicators.ts';

interface MacdEmaState {
  ema: EMA;
  macd: MACD;
  reopenDirection: 'BUY' | 'SELL' | null;
}

export interface MacdEmaParams {
  name: string;
  timeframe: Timeframe;
  emaPeriod: number;
  tpReturn: number;
  leverage: number;
  slReturn?: number;
  macdFast?: number;
  macdSlow?: number;
  macdSignal?: number;
}

function computeSize(ctx: Context, price: number): number | null {
  const { leverage, minSize, maxSize, sizeIncrement } = ctx.instrument;
  let size = (ctx.account.available * leverage) / price;
  size = Math.min(size, maxSize);
  size = Math.floor(size / sizeIncrement) * sizeIncrement;
  return size >= minSize ? size : null;
}

export function createMacdEmaAgent(params: MacdEmaParams): Agent<MacdEmaState> {
  const config: AgentConfig = {
    name: params.name,
    version: '1.0.0',
    instrument: 'US100',
    primaryFeed: params.timeframe,
    leverage: params.leverage,
  };

  function init(): MacdEmaState {
    return {
      ema: new EMA(params.emaPeriod),
      macd: new MACD(params.macdFast ?? 12, params.macdSlow ?? 26, params.macdSignal ?? 9),
      reopenDirection: null,
    };
  }

  function onCandle(
    candle: Candle,
    ctx: Context,
    state: MacdEmaState,
  ): AgentResult<MacdEmaState> {
    const price = candle.close;

    // Update indicators
    state.ema.update(price);
    state.macd.update(price);

    // Reopen after day-end close
    if (state.reopenDirection && !ctx.position) {
      const size = computeSize(ctx, price);
      if (size === null) {
        state.reopenDirection = null;
        return { order: null, state };
      }
      const dir = state.reopenDirection;
      state.reopenDirection = null;
      return {
        order: { action: 'OPEN', side: dir, size, stopLossReturn: params.slReturn ?? -0.50, takeProfitReturn: params.tpReturn },
        state,
      };
    }

    // Need both indicators ready and no open position
    if (!state.ema.ready || !state.macd.ready || ctx.position) {
      return { order: null, state };
    }

    const trend = price > state.ema.value ? 'UP' : 'DOWN';

    // Enter on MACD crossover in direction of EMA trend
    if (trend === 'UP' && state.macd.bullishCross) {
      const size = computeSize(ctx, price);
      if (size !== null) {
        return {
          order: { action: 'OPEN', side: 'BUY', size, stopLossReturn: params.slReturn ?? -0.50, takeProfitReturn: params.tpReturn },
          state,
        };
      }
    }

    if (trend === 'DOWN' && state.macd.bearishCross) {
      const size = computeSize(ctx, price);
      if (size !== null) {
        return {
          order: { action: 'OPEN', side: 'SELL', size, stopLossReturn: params.slReturn ?? -0.50, takeProfitReturn: params.tpReturn },
          state,
        };
      }
    }

    return { order: null, state };
  }

  function onFill(fill: Fill, state: MacdEmaState): MacdEmaState {
    if (fill.action === 'CLOSED') {
      if (fill.reason === 'MARKET_CLOSE') {
        state.reopenDirection = fill.side === 'SELL' ? 'BUY' : 'SELL';
      } else {
        state.reopenDirection = null;
      }
    }
    return state;
  }

  return { config, init, onCandle, onFill };
}


// FILE: apps/backend/agents/trend-follower/blueprint.ts
/**
 * Trend Follower blueprint.
 *
 * Generates agents across two dimension sweeps × leverage:
 *   1. trendPct sweep (4 TFs × 8–9 thresholds, default TP)
 *   2. TP sweep (4 TFs × 9 TP values, fixed trendPct=1.5%)
 *   × 2 leverage values = 142 agents
 *
 * Factory logic lives in factory.ts (also used by batch runners).
 */
import type { AgentBlueprint, Dimension } from '../../src/core/agent/types.ts';
import { createAgent } from './factory.ts';

// --- Dimension generation ---

type TrendDim = Dimension & {
  timeframe: string;
  trendPct: number;
  leverage: number;
  tpReturn?: number;
};

const TIMEFRAMES = ['1m', '5m', '15m', '1h', '4h'] as const;
const LEVERAGES = [20, 200] as const;

// trendPct values per timeframe (1m stops at 2.00%, others go to 3.00%)
const TREND_PCTS: Record<string, number[]> = {
  '1m': [0.0025, 0.005, 0.0075, 0.01, 0.0125, 0.015, 0.0175, 0.02],
  '5m': [0.0025, 0.005, 0.0075, 0.01, 0.0125, 0.015, 0.0175, 0.02, 0.03],
  '15m': [0.0025, 0.005, 0.0075, 0.01, 0.0125, 0.015, 0.0175, 0.02, 0.03],
  '1h': [0.0025, 0.005, 0.0075, 0.01, 0.0125, 0.015, 0.0175, 0.02, 0.03],
  '4h': [0.0025, 0.005, 0.0075, 0.01, 0.0125, 0.015, 0.0175, 0.02, 0.03],
};

// TP-sweep: fixed trendPct, varying tpReturn
const TP_SWEEP_TREND_PCT = 0.015;
const TP_RETURNS = [0.05, 0.10, 0.15, 0.20, 0.25, 0.30, 0.35, 0.40, 0.50];
const TP_LABELS = ['025', '050', '075', '100', '125', '150', '175', '200', '250'];

function pctLabel(pct: number): string {
  // 0.0025 → "025" (0.25%), 0.005 → "050" (0.50%), 0.03 → "300" (3.00%)
  return String(Math.round(pct * 10000)).padStart(3, '0');
}

const dimensions: TrendDim[] = [];

// Standard trendPct sweep (default TP = +100% margin)
for (const lev of LEVERAGES) {
  for (const tf of TIMEFRAMES) {
    for (const trendPct of TREND_PCTS[tf]!) {
      dimensions.push({
        id: `${tf}-${pctLabel(trendPct)}-lev${lev}`,
        timeframe: tf,
        trendPct,
        leverage: lev,
      });
    }
  }
}

// TP sweep (fixed trendPct, varying TP)
for (const lev of LEVERAGES) {
  for (const tf of TIMEFRAMES) {
    for (let i = 0; i < TP_RETURNS.length; i++) {
      dimensions.push({
        id: `tp-sweep/${tf}-tp${TP_LABELS[i]}-lev${lev}`,
        timeframe: tf,
        trendPct: TP_SWEEP_TREND_PCT,
        tpReturn: TP_RETURNS[i],
        leverage: lev,
      });
    }
  }
}

// --- Blueprint export ---

export default {
  name: 'Trend Follower',
  version: '1.0.0',
  instrument: 'US100',
  dimensions,
  createAgent(dim: TrendDim) {
    const pctStr = (dim.trendPct * 100).toFixed(2);
    let name = `Trend ${dim.timeframe} ${pctStr}% lev${dim.leverage}`;
    if (dim.tpReturn != null) {
      const tpStr = (dim.tpReturn * 100).toFixed(2);
      name = `Trend ${dim.timeframe} t${pctStr}% tp${tpStr}% lev${dim.leverage}`;
    }
    return createAgent({
      name,
      timeframe: dim.timeframe as any,
      trendPct: dim.trendPct,
      leverage: dim.leverage,
      tpReturn: dim.tpReturn,
    });
  },
} satisfies AgentBlueprint<any>;


// FILE: apps/backend/agents/trend-follower/factory-v2.ts
/**
 * Trend-follower v2 — reopens after forced day-end close.
 *
 * Behavior:
 *   - Opens when price moves trendPct% in one direction from swing point.
 *   - SL at -50% margin, TP configurable.
 *   - If force-closed at day end (MARKET_CLOSE), reopens same direction on next candle.
 *   - Only SL or TP resolves the trade idea — day close is just an interruption.
 */
import type {
  Agent,
  AgentConfig,
  Candle,
  Context,
  AgentResult,
  Fill,
  Timeframe,
} from '../../src/core/agent/types.ts';

interface TrendState {
  swingHigh: number;
  swingLow: number;
  ready: boolean;
  /** If set, reopen in this direction on next candle (after day-end close). */
  reopenDirection: 'BUY' | 'SELL' | null;
}

export interface V2Params {
  name: string;
  timeframe: Timeframe;
  trendPct: number;
  tpReturn: number;
}

const SL_RETURN = -0.50;

/** Compute all-in size, returns null if can't afford minSize. */
function computeSize(ctx: Context, price: number): number | null {
  const { leverage, minSize, maxSize, sizeIncrement } = ctx.instrument;
  let size = (ctx.account.available * leverage) / price;
  size = Math.min(size, maxSize);
  size = Math.floor(size / sizeIncrement) * sizeIncrement;
  return size >= minSize ? size : null;
}

export function createAgentV2(params: V2Params): Agent<TrendState> {
  const config: AgentConfig = {
    name: params.name,
    version: '2.0.0',
    instrument: 'US100',
    primaryFeed: params.timeframe,
    maxDrawdown: undefined,
  };

  function init(): TrendState {
    return { swingHigh: 0, swingLow: Infinity, ready: false, reopenDirection: null };
  }

  function onCandle(
    candle: Candle,
    ctx: Context,
    state: TrendState,
  ): AgentResult<TrendState> {
    const price = candle.close;

    if (!state.ready) {
      return {
        order: null,
        state: { swingHigh: price, swingLow: price, ready: true, reopenDirection: null },
      };
    }

    // Reopen after day-end close
    if (state.reopenDirection && !ctx.position) {
      const size = computeSize(ctx, price);
      if (size === null) {
        // Can't afford minimum position — abandon trade idea
        return { order: null, state: { swingHigh: price, swingLow: price, ready: true, reopenDirection: null } };
      }

      return {
        order: {
          action: 'OPEN',
          side: state.reopenDirection,
          size,
          stopLossReturn: SL_RETURN,
          takeProfitReturn: params.tpReturn,
        },
        state: { swingHigh: price, swingLow: price, ready: true, reopenDirection: null },
      };
    }

    const swingHigh = Math.max(state.swingHigh, price);
    const swingLow = Math.min(state.swingLow, price);

    if (ctx.position) {
      return { order: null, state: { ...state, swingHigh, swingLow } };
    }

    const upMove = (price - swingLow) / swingLow;
    const downMove = (swingHigh - price) / swingHigh;

    if (upMove >= params.trendPct && downMove < params.trendPct) {
      const size = computeSize(ctx, price);
      if (size !== null) {
        return {
          order: {
            action: 'OPEN',
            side: 'BUY',
            size,
            stopLossReturn: SL_RETURN,
            takeProfitReturn: params.tpReturn,
          },
          state: { swingHigh: price, swingLow: price, ready: true, reopenDirection: null },
        };
      }
    }

    if (downMove >= params.trendPct && upMove < params.trendPct) {
      const size = computeSize(ctx, price);
      if (size !== null) {
        return {
          order: {
            action: 'OPEN',
            side: 'SELL',
            size,
            stopLossReturn: SL_RETURN,
            takeProfitReturn: params.tpReturn,
          },
          state: { swingHigh: price, swingLow: price, ready: true, reopenDirection: null },
        };
      }
    }

    return { order: null, state: { ...state, swingHigh, swingLow } };
  }

  function onFill(fill: Fill, state: TrendState): TrendState {
    if (fill.action === 'CLOSED') {
      if (fill.reason === 'MARKET_CLOSE') {
        // Day-end close — reopen same direction on next candle.
        // fill.side is the CLOSING side, so original direction is the opposite.
        const originalDir = fill.side === 'SELL' ? 'BUY' : 'SELL';
        return { swingHigh: fill.price, swingLow: fill.price, ready: true, reopenDirection: originalDir };
      }
      // SL or TP — trade idea resolved, start fresh.
      return { swingHigh: fill.price, swingLow: fill.price, ready: true, reopenDirection: null };
    }
    return state;
  }

  return { config, init, onCandle, onFill };
}


// FILE: apps/backend/agents/trend-follower/factory.ts
/**
 * Shared logic for trend-follower variants.
 * Each variant just calls createAgent() with different params.
 */
import type {
  Agent,
  AgentConfig,
  Candle,
  Context,
  AgentResult,
  Fill,
  Timeframe,
} from '../../src/core/agent/types.ts';

interface TrendState {
  swingHigh: number;
  swingLow: number;
  ready: boolean;
}

interface Params {
  name: string;
  timeframe: Timeframe;
  trendPct: number;
  leverage: number;
  /** Margin-return target for take profit. Default +100% of margin. */
  tpReturn?: number;
}

// Agent specifies margin-return targets — framework computes exact prices after fill.
const SL_RETURN = -0.50;  // -50% of margin
const DEFAULT_TP_RETURN = 1.00;   // +100% of margin

export function createAgent(params: Params): Agent<TrendState> {
  const config: AgentConfig = {
    name: params.name,
    version: '1.0.0',
    instrument: 'US100',
    primaryFeed: params.timeframe,
    maxDrawdown: 0.50,
    leverage: params.leverage,
  };

  function init(): TrendState {
    return { swingHigh: 0, swingLow: Infinity, ready: false };
  }

  function onCandle(
    candle: Candle,
    ctx: Context,
    state: TrendState,
  ): AgentResult<TrendState> {
    const price = candle.close;

    if (!state.ready) {
      return {
        order: null,
        state: { swingHigh: price, swingLow: price, ready: true },
      };
    }

    const swingHigh = Math.max(state.swingHigh, price);
    const swingLow = Math.min(state.swingLow, price);

    if (ctx.position) {
      return { order: null, state: { swingHigh, swingLow, ready: true } };
    }

    const upMove = (price - swingLow) / swingLow;
    const downMove = (swingHigh - price) / swingHigh;

    if (upMove >= params.trendPct && downMove < params.trendPct) {
      const { leverage, minSize, maxSize, sizeIncrement } = ctx.instrument;

      let size = (ctx.account.available * leverage) / price;
      size = Math.min(size, maxSize);
      size = Math.max(size, minSize);
      size = Math.floor(size / sizeIncrement) * sizeIncrement;

      return {
        order: {
          action: 'OPEN',
          side: 'BUY',
          size,
          stopLossReturn: SL_RETURN,
          takeProfitReturn: params.tpReturn ?? DEFAULT_TP_RETURN,
        },
        state: { swingHigh: price, swingLow: price, ready: true },
      };
    }

    if (downMove >= params.trendPct && upMove < params.trendPct) {
      const { leverage, minSize, maxSize, sizeIncrement } = ctx.instrument;

      let size = (ctx.account.available * leverage) / price;
      size = Math.min(size, maxSize);
      size = Math.max(size, minSize);
      size = Math.floor(size / sizeIncrement) * sizeIncrement;

      return {
        order: {
          action: 'OPEN',
          side: 'SELL',
          size,
          stopLossReturn: SL_RETURN,
          takeProfitReturn: params.tpReturn ?? DEFAULT_TP_RETURN,
        },
        state: { swingHigh: price, swingLow: price, ready: true },
      };
    }

    return { order: null, state: { swingHigh, swingLow, ready: true } };
  }

  function onFill(fill: Fill, state: TrendState): TrendState {
    if (fill.action === 'CLOSED') {
      return { swingHigh: fill.price, swingLow: fill.price, ready: true };
    }
    return state;
  }

  return { config, init, onCandle, onFill };
}


