        expect(result).toBeNull();
      }

      // Minute 15 starts new bucket
      const completed = builder.addMinuteCandle(minute(15));
      expect(completed).not.toBeNull();
      expect(completed!.timeframe).toBe('15m');
      expect(completed!.timestamp).toBe(0);
    });
  });

