// FILE: apps/backend/src/core/execution/SimulatedExecution.ts
import type { Fill, FillReason, InstrumentInfo, Position } from '../agent/types.ts';
import type { Trigger } from '../position/PositionMonitor.ts';
import type { ExecutionEngine } from './types.ts';
import { TickGenerator } from '../feed/TickGenerator.ts';

export type SlippageMode =
  | { type: 'none' }
  | { type: 'fixed'; amount: number }
  | { type: 'random'; maxAmount: number }
  | { type: 'realistic'; minDelayMs?: number; maxDelayMs?: number };

export class SimulatedExecution implements ExecutionEngine {
  private readonly instrument: InstrumentInfo;
  private readonly slippage: SlippageMode;
  private readonly tickGenerator: TickGenerator | null;

  constructor(instrument: InstrumentInfo, slippage: SlippageMode = { type: 'none' }) {
    this.instrument = instrument;
    this.slippage = slippage;
    this.tickGenerator = slippage.type === 'realistic'
      ? TickGenerator.fromInstrument(instrument)
      : null;
  }

  /**
   * Execute an OPEN order.
   *
   * referencePrice is the candle close (bid-side).
   * BUY fills at ask (= reference + spread) + slippage.
   * SELL fills at bid (= reference) - slippage.
   */
  async executeOpen(
    side: 'BUY' | 'SELL',
    size: number,
    referencePrice: number,
    timestamp: number,
  ): Promise<Fill> {
    let price: number;

    if (this.slippage.type === 'realistic') {
      const bid = referencePrice;
      const ask = referencePrice + this.instrument.spread;
      price = this.simulateRealisticFill(bid, ask, side);
    } else {
      const slip = this.getSlippage();
      if (side === 'BUY') {
        price = referencePrice + this.instrument.spread + slip;
      } else {
        price = referencePrice - slip;
      }
    }

    price = this.roundPrice(price);

    return {
      action: 'OPENED',
      reason: 'ORDER',
      side,
      size,
      price,
      timestamp,
    };
  }

  /**
   * Execute a CLOSE order (agent requested).
   *
   * BUY position closes by selling at bid (= reference) - slippage.
   * SELL position closes by buying at ask (= reference + spread) + slippage.
   */
  async executeClose(
    position: Position,
    referencePrice: number,
    timestamp: number,
  ): Promise<Fill> {
    let exitPrice: number;
    const closeSide: 'BUY' | 'SELL' = position.direction === 'BUY' ? 'SELL' : 'BUY';

    if (this.slippage.type === 'realistic') {
      const bid = referencePrice;
      const ask = referencePrice + this.instrument.spread;
      exitPrice = this.simulateRealisticFill(bid, ask, closeSide);
    } else {
      const slip = this.getSlippage();
      if (position.direction === 'BUY') {
        // Sell at bid - slippage
        exitPrice = referencePrice - slip;
      } else {
        // Buy back at ask + slippage
        exitPrice = referencePrice + this.instrument.spread + slip;
      }
    }

    exitPrice = this.roundPrice(exitPrice);
    const pnl = this.calculatePnL(position, exitPrice);

    return {
      action: 'CLOSED',
      reason: 'ORDER',
      side: closeSide,
      size: position.size,
      price: exitPrice,
      timestamp,
      pnl,
    };
  }

  /**
   * Execute a triggered close (stop loss, take profit, liquidation, market close).
   *
   * Stop loss / liquidation / market close: adverse slippage (or realistic simulation).
   * Take profit: fills at exactly the trigger price (limit order, no slippage).
   */
  async executeTrigger(
    trigger: Trigger,
    position: Position,
    timestamp: number,
  ): Promise<Fill> {
    const closeSide: 'BUY' | 'SELL' = position.direction === 'BUY' ? 'SELL' : 'BUY';
    let exitPrice: number;

    if (trigger.reason === 'TAKE_PROFIT') {
      // Limit order: fills at exactly the TP level
      exitPrice = trigger.price;
    } else if (this.slippage.type === 'realistic') {
      // Simulate price movement during execution delay.
      // trigger.price is bid-side for BUY positions, ask-side for SELL positions.
      let bid: number, ask: number;
      if (position.direction === 'BUY') {
        bid = trigger.price;
        ask = trigger.price + this.instrument.spread;
      } else {
        ask = trigger.price;
        bid = trigger.price - this.instrument.spread;
      }
      exitPrice = this.simulateRealisticFill(bid, ask, closeSide);
    } else {
      // Stop / liquidation / market close: adverse slippage
      const slip = this.getSlippage();
      if (position.direction === 'BUY') {
        // Selling: price slips down (worse for us)
        exitPrice = trigger.price - slip;
      } else {
        // Buying back: price slips up (worse for us)
        exitPrice = trigger.price + slip;
      }
    }

    exitPrice = this.roundPrice(exitPrice);
    const pnl = this.calculatePnL(position, exitPrice);

    return {
      action: 'CLOSED',
      reason: trigger.reason,
      side: closeSide,
      size: position.size,
      price: exitPrice,
      timestamp,
      pnl,
    };
  }

  /**
   * Simulate realistic price movement over a random 200–500ms delay
   * using the tick generator. Returns the fill price from the last tick.
   *
   * fillSide is the side of the fill: BUY → fill at ask, SELL → fill at bid.
   */
  private simulateRealisticFill(referenceBid: number, referenceAsk: number, fillSide: 'BUY' | 'SELL'): number {
    if (this.slippage.type !== 'realistic') {
      throw new Error('simulateRealisticFill called without realistic slippage');
    }

    const minDelay = this.slippage.minDelayMs ?? 200;
    const maxDelay = this.slippage.maxDelayMs ?? 500;
    const delayMs = minDelay + Math.random() * (maxDelay - minDelay);

    const ticks = this.tickGenerator!.generateForDuration(referenceBid, referenceAsk, 0, delayMs);

    if (ticks.length === 0) {
      return fillSide === 'BUY' ? referenceAsk : referenceBid;
    }

    const lastTick = ticks[ticks.length - 1];
    return fillSide === 'BUY' ? lastTick.ask : lastTick.bid;
  }

  private calculatePnL(position: Position, exitPrice: number): number {
    const { direction, size, entryPrice } = position;
    const lotSize = this.instrument.lotSize;

    if (direction === 'BUY') {
      return (exitPrice - entryPrice) * size * lotSize;
    } else {
      return (entryPrice - exitPrice) * size * lotSize;
    }
  }

  private getSlippage(): number {
    switch (this.slippage.type) {
      case 'none':
        return 0;
      case 'fixed':
        return this.slippage.amount;
      case 'random':
        return Math.random() * this.slippage.maxAmount;
      case 'realistic':
        // Realistic mode uses simulateRealisticFill, not this method
        return 0;
    }
  }

  private roundPrice(price: number): number {
    const factor = Math.pow(10, this.instrument.pricePrecision);
    return Math.round(price * factor) / factor;
  }
}


// FILE: apps/backend/src/core/execution/types.ts
import type { Fill, InstrumentInfo, Position } from '../agent/types.ts';
import type { Trigger } from '../position/PositionMonitor.ts';

/**
 * Common interface for all execution engines.
 *
 * SimulatedExecution: fills at simulated prices with configurable slippage.
 * CapitalLiveExecution: fills via Capital.com REST API.
 *
 * All methods are async to support network-based implementations.
 */
export interface ExecutionEngine {
  executeOpen(
    side: 'BUY' | 'SELL',
    size: number,
    referencePrice: number,
    timestamp: number,
  ): Promise<Fill>;

  executeClose(
    position: Position,
    referencePrice: number,
    timestamp: number,
  ): Promise<Fill>;

  executeTrigger(
    trigger: Trigger,
    position: Position,
    timestamp: number,
  ): Promise<Fill>;
}


