import type { FillReason, Position } from '../agent/types.ts';

export interface Trigger {
  reason: FillReason;
  price: number;
}

export class PositionMonitor {
  private position: Position | null = null;
  private liquidationPrice: number | null = null;

  setPosition(position: Position | null, liquidationPrice?: number): void {
    this.position = position;
    this.liquidationPrice = position ? (liquidationPrice ?? null) : null;
  }

  getPosition(): Position | null {
    return this.position;
  }

  /**
   * Check a price update against the current position's stops/TP and equity.
   *
   * For BUY positions: stop/TP check against bid (sell side).
   * For SELL positions: stop/TP check against ask (buy-back side).
   *
   * Pessimistic: if both stop and TP could trigger, stop wins.
   * Liquidation (equity <= 0) takes priority over everything.
   *
   * Returns a Trigger if something fires, null otherwise.
   */
  check(bid: number, ask: number, equity: number): Trigger | null {
    if (!this.position) return null;

    // Margin liquidation: position loss exceeded margin threshold
    if (this.liquidationPrice !== null) {
      if (this.position.direction === 'BUY' && bid <= this.liquidationPrice) {
        return { reason: 'LIQUIDATION', price: this.liquidationPrice };
      }
      if (this.position.direction === 'SELL' && ask >= this.liquidationPrice) {
        return { reason: 'LIQUIDATION', price: this.liquidationPrice };
      }
    }

    // Account-level liquidation (fallback — entire account equity gone)
    if (equity <= 0) {
      const price = this.position.direction === 'BUY' ? bid : ask;
      return { reason: 'LIQUIDATION', price };
    }

    const { direction, stopLoss, takeProfit } = this.position;

    let stopTriggered = false;
    let tpTriggered = false;

    if (direction === 'BUY') {
      // Would sell at bid to exit
      if (stopLoss !== undefined && bid <= stopLoss) stopTriggered = true;
      if (takeProfit !== undefined && bid >= takeProfit) tpTriggered = true;
    } else {
      // Would buy back at ask to exit
      if (stopLoss !== undefined && ask >= stopLoss) stopTriggered = true;
      if (takeProfit !== undefined && ask <= takeProfit) tpTriggered = true;
    }

    // Pessimistic: stop wins over TP
    if (stopTriggered) {
      const price = stopLoss!;
      return { reason: 'STOP_LOSS', price };
    }

    if (tpTriggered) {
      const price = takeProfit!;
      return { reason: 'TAKE_PROFIT', price };
    }

    return null;
  }

  /**
   * Check a backtest candle against stops/TP.
   * Uses the candle's high and low to determine if stops/TP were breached.
   *
   * candleLow/candleHigh are bid-side prices (from stored OHLC).
   * spread is added for SELL position ask-side checks.
   */
  checkCandle(
    candleLow: number,
    candleHigh: number,
    spread: number,
    equity: number,
  ): Trigger | null {
    if (!this.position) return null;

    const { direction, stopLoss, takeProfit } = this.position;

    // Margin liquidation: position loss exceeded margin threshold
    if (this.liquidationPrice !== null) {
      if (direction === 'BUY' && candleLow <= this.liquidationPrice) {
        return { reason: 'LIQUIDATION', price: this.liquidationPrice };
      }
      if (direction === 'SELL' && (candleHigh + spread) >= this.liquidationPrice) {
        return { reason: 'LIQUIDATION', price: this.liquidationPrice };
      }
    }

    // Account-level liquidation (fallback — entire account equity gone)
    if (equity <= 0) {
      const price = direction === 'BUY' ? candleLow : candleHigh + spread;
      return { reason: 'LIQUIDATION', price };
    }

    let stopTriggered = false;
    let tpTriggered = false;

    if (direction === 'BUY') {
      // Exit at bid side
      if (stopLoss !== undefined && candleLow <= stopLoss) stopTriggered = true;
      if (takeProfit !== undefined && candleHigh >= takeProfit) tpTriggered = true;
    } else {
      // Exit at ask side (bid + spread)
      const askLow = candleLow + spread;
      const askHigh = candleHigh + spread;
      if (stopLoss !== undefined && askHigh >= stopLoss) stopTriggered = true;
      if (takeProfit !== undefined && askLow <= takeProfit) tpTriggered = true;
    }

    // Pessimistic: stop wins
    if (stopTriggered) {
      return { reason: 'STOP_LOSS', price: stopLoss! };
    }

    if (tpTriggered) {
      return { reason: 'TAKE_PROFIT', price: takeProfit! };
    }

    return null;
  }
}


// FILE: apps/backend/src/data/CandleRepository.ts
import type { Candle } from '../core/agent/types.ts';
import { sql } from './db.ts';

export class CandleRepository {
  /**
   * Load minute candles from the database for a given instrument and date range.
   * Returns candles sorted by timestamp ascending.
   */
  static async loadMinuteCandles(
    instrument: string,
    startMs: number,
    endMs: number,
  ): Promise<Candle[]> {
    const rows = await sql`
      SELECT timestamp, open, high, low, close
      FROM candles
      WHERE instrument = ${instrument}
        AND timestamp >= ${startMs}
        AND timestamp <= ${endMs}
      ORDER BY timestamp ASC
    `;

    return rows.map(row => ({
      open: Number(row.open),
      high: Number(row.high),
      low: Number(row.low),
      close: Number(row.close),
      timestamp: Number(row.timestamp),
      timeframe: '1m' as const,
    }));
  }

  /**
   * Insert minute candles into the database.
   * Uses ON CONFLICT DO NOTHING for idempotent inserts.
   */
  static async insertCandles(instrument: string, candles: Candle[]): Promise<number> {
    if (candles.length === 0) return 0;

    let inserted = 0;

    // Batch insert in chunks of 500
    for (let i = 0; i < candles.length; i += 500) {
      const batch = candles.slice(i, i + 500);
      const values = batch.map(c => ({
        instrument,
        timestamp: c.timestamp,
        open: c.open,
        high: c.high,
        low: c.low,
        close: c.close,
      }));

      await sql`
        INSERT INTO candles ${sql(values)}
        ON CONFLICT (instrument, timestamp) DO NOTHING
      `;

      inserted += batch.length;
    }

    return inserted;
  }

  /**
   * Get the latest candle timestamp for an instrument.
   * Returns null if no candles exist.
   */
  static async getLatestTimestamp(instrument: string): Promise<number | null> {
    const rows = await sql`
      SELECT MAX(timestamp) as latest
      FROM candles
      WHERE instrument = ${instrument}
    `;

    const latest = rows[0]?.latest;
    return latest !== null && latest !== undefined ? Number(latest) : null;
  }

  static async getEarliestTimestamp(instrument: string): Promise<number | null> {
    const rows = await sql`
      SELECT MIN(timestamp) as earliest
      FROM candles
      WHERE instrument = ${instrument}
    `;

    const earliest = rows[0]?.earliest;
    return earliest !== null && earliest !== undefined ? Number(earliest) : null;
  }
}


// FILE: apps/backend/src/data/RunRepository.ts
import type { Fill } from '../core/agent/types.ts';
import type { EquityPoint } from '../core/agent/AgentRunner.ts';
import type { Metrics } from '../core/metrics/MetricsEngine.ts';
import { sql } from './db.ts';

export interface RunRecord {
  id: string;
  agentId: string;
  agentName: string;
  mode: string;
  status: string;
  capital: number;
  instrument: string;
  config: Record<string, unknown>;
  startedAt: number | null;
  completedAt: number | null;
  metrics: Metrics | null;
}

export class RunRepository {
  static async createRun(run: Omit<RunRecord, 'completedAt' | 'metrics'>): Promise<void> {
    await sql`
      INSERT INTO runs (id, agent_id, agent_name, mode, status, capital, instrument, config, started_at)
      VALUES (${run.id}, ${run.agentId}, ${run.agentName}, ${run.mode}, ${run.status},
              ${run.capital}, ${run.instrument}, ${JSON.stringify(run.config)}, ${run.startedAt})
    `;
  }

  static async completeRun(runId: string, metrics: Metrics): Promise<void> {
    await sql`
      UPDATE runs
      SET status = 'completed',
          completed_at = ${Date.now()},
          metrics = ${JSON.stringify(metrics)}
      WHERE id = ${runId}
    `;
  }

  static async updateRunStatus(runId: string, status: string, startedAt?: number): Promise<void> {
    if (startedAt !== undefined) {
      await sql`
        UPDATE runs SET status = ${status}, started_at = ${startedAt} WHERE id = ${runId}
      `;
    } else {
      await sql`
        UPDATE runs SET status = ${status} WHERE id = ${runId}
      `;
    }
  }

  static async getActiveRuns(): Promise<RunRecord[]> {
    const rows = await sql`
      SELECT * FROM runs
      WHERE status IN ('queued', 'running') AND mode = 'backtest'
      ORDER BY started_at ASC NULLS LAST
    `;
    return rows.map(row => this.mapRow(row));
  }

  static async failRun(runId: string, error: string): Promise<void> {
    await sql`
      UPDATE runs
      SET status = 'error',
          completed_at = ${Date.now()},
          metrics = ${JSON.stringify({ error })}
      WHERE id = ${runId}
    `;
  }

  static async saveFills(runId: string, fills: Fill[]): Promise<void> {
    if (fills.length === 0) return;

    const values = fills.map(f => ({
      run_id: runId,
      action: f.action,
      reason: f.reason,
      side: f.side,
      size: f.size,
      price: f.price,
      pnl: f.pnl ?? null,
      timestamp: f.timestamp,
    }));

    for (let i = 0; i < values.length; i += 500) {
      const batch = values.slice(i, i + 500);
      await sql`INSERT INTO fills ${sql(batch)}`;
    }
  }

  static async saveEquityCurve(runId: string, curve: EquityPoint[]): Promise<void> {
    if (curve.length === 0) return;

    const values = curve.map(p => ({
      run_id: runId,
      timestamp: p.timestamp,
      equity: p.equity,
      balance: p.balance,
    }));

    for (let i = 0; i < values.length; i += 500) {
      const batch = values.slice(i, i + 500);
      await sql`
        INSERT INTO equity_snapshots ${sql(batch)}
        ON CONFLICT (run_id, timestamp) DO NOTHING
      `;
    }
  }

  static async getRun(runId: string): Promise<RunRecord | null> {
    const rows = await sql`SELECT * FROM runs WHERE id = ${runId}`;
    if (rows.length === 0) return null;

    const row = rows[0]!;
    return {
      id: row.id as string,
      agentId: row.agent_id as string,
      agentName: row.agent_name as string,
      mode: row.mode as string,
      status: row.status as string,
      capital: Number(row.capital),
      instrument: row.instrument as string,
      config: row.config as Record<string, unknown>,
      startedAt: row.started_at ? Number(row.started_at) : null,
      completedAt: row.completed_at ? Number(row.completed_at) : null,
      metrics: row.metrics as Metrics | null,
    };
  }

  static async listRuns(filters?: {
    mode?: string;
    status?: string;
    agentId?: string;
  }): Promise<RunRecord[]> {
    let query = sql`SELECT * FROM runs WHERE 1=1`;

    // Build filtered query
    if (filters?.mode && filters?.status && filters?.agentId) {
      query = sql`SELECT * FROM runs WHERE mode = ${filters.mode} AND status = ${filters.status} AND agent_id = ${filters.agentId} ORDER BY started_at DESC`;
    } else if (filters?.mode && filters?.status) {
      query = sql`SELECT * FROM runs WHERE mode = ${filters.mode} AND status = ${filters.status} ORDER BY started_at DESC`;
    } else if (filters?.mode) {
      query = sql`SELECT * FROM runs WHERE mode = ${filters.mode} ORDER BY started_at DESC`;
    } else if (filters?.status) {
      query = sql`SELECT * FROM runs WHERE status = ${filters.status} ORDER BY started_at DESC`;
    } else if (filters?.agentId) {
      query = sql`SELECT * FROM runs WHERE agent_id = ${filters.agentId} ORDER BY started_at DESC`;
    } else {
      query = sql`SELECT * FROM runs ORDER BY started_at DESC`;
    }

    const rows = await query;
    return rows.map(row => this.mapRow(row));
  }

  static async getFills(runId: string): Promise<Fill[]> {
    const rows = await sql`
      SELECT action, reason, side, size, price, pnl, timestamp
      FROM fills
      WHERE run_id = ${runId}
      ORDER BY timestamp ASC
    `;

    return rows.map(row => ({
      action: row.action as Fill['action'],
      reason: row.reason as Fill['reason'],
      side: row.side as Fill['side'],
      size: Number(row.size),
      price: Number(row.price),
      pnl: row.pnl !== null ? Number(row.pnl) : undefined,
      timestamp: Number(row.timestamp),
    }));
  }

  static async getEquityCurve(runId: string): Promise<EquityPoint[]> {
    const rows = await sql`
      SELECT timestamp, equity, balance
      FROM equity_snapshots
      WHERE run_id = ${runId}
      ORDER BY timestamp ASC
    `;

    return rows.map(row => ({
      timestamp: Number(row.timestamp),
      equity: Number(row.equity),
      balance: Number(row.balance),
    }));
  }

  static async getLeaderboard(sortBy: string = 'totalReturn'): Promise<RunRecord[]> {
    // Only completed runs with metrics
    const rows = await sql`
      SELECT * FROM runs
      WHERE status = 'completed' AND metrics IS NOT NULL
      ORDER BY started_at DESC
    `;

    const records = rows.map(row => this.mapRow(row));

    // Sort by the requested metric (descending = best first)
    const metricKey = sortBy as keyof Metrics;
    records.sort((a, b) => {
      const aVal = a.metrics?.[metricKey] ?? 0;
      const bVal = b.metrics?.[metricKey] ?? 0;
      // For maxDrawdown and averageLoss, lower is better — but we still sort descending
      // and let the consumer interpret. Leaderboard default = totalReturn descending.
      return (bVal as number) - (aVal as number);
    });

    return records;
  }

  private static mapRow(row: Record<string, unknown>): RunRecord {
    return {
      id: row.id as string,
      agentId: row.agent_id as string,
      agentName: row.agent_name as string,
      mode: row.mode as string,
      status: row.status as string,
      capital: Number(row.capital),
      instrument: row.instrument as string,
      config: row.config as Record<string, unknown>,
      startedAt: row.started_at ? Number(row.started_at) : null,
      completedAt: row.completed_at ? Number(row.completed_at) : null,
      metrics: row.metrics as Metrics | null,
    };
  }
}


