import type { Candle } from '../../core/agent/types.ts';
import type { MinuteCandleHandler, PriceFeed } from '../../core/feed/types.ts';
import type { CapitalSession } from './CapitalSession.ts';

export type TickHandler = (bid: number, ask: number, timestamp: number) => void;

interface CapitalLiveFeedConfig {
  session: CapitalSession;
  epic: string;
  onTick?: TickHandler;
}

const PING_INTERVAL_MS = 60_000;
const RECONNECT_DELAY_MS = 3_000;

/**
 * Live price feed via Capital.com WebSocket.
 *
 * Connects to the streaming API, subscribes to quotes for a single epic,
 * accumulates ticks into minute candles, and emits completed candles
 * when a new minute bucket starts.
 *
 * Also calls onTick for every quote so the runner can check stops/TPs
 * in real-time.
 */
export class CapitalLiveFeed implements PriceFeed {
  private readonly session: CapitalSession;
  private readonly epic: string;
  private readonly onTick?: TickHandler;

  private ws: WebSocket | null = null;
  private pingTimer: ReturnType<typeof setInterval> | null = null;
  private stopped: boolean = false;
  private resolveStart: (() => void) | null = null;

  // Minute candle accumulation
  private currentBucket: number = 0;  // floor(ts / 60000) * 60000
  private currentCandle: { open: number; high: number; low: number; close: number } | null = null;
  private handler: MinuteCandleHandler | null = null;

  constructor(config: CapitalLiveFeedConfig) {
    this.session = config.session;
    this.epic = config.epic;
    this.onTick = config.onTick;
  }

  async start(handler: MinuteCandleHandler): Promise<void> {
    this.handler = handler;
    this.stopped = false;

    return new Promise<void>((resolve) => {
      this.resolveStart = resolve;
      this.connect();
    });
  }

  stop(): void {
    this.stopped = true;

    // Flush partial candle
    if (this.currentCandle && this.handler) {
      const candle = this.buildCandle(this.currentBucket);
      this.handler(candle);
      this.currentCandle = null;
    }

    this.cleanup();

    if (this.resolveStart) {
      this.resolveStart();
      this.resolveStart = null;
    }
  }

  /**
   * Process a raw tick (bid mid-price). Public for testability.
   */
  processTick(bid: number, ask: number, timestamp: number): void {
    const mid = (bid + ask) / 2;
    const bucket = Math.floor(timestamp / 60_000) * 60_000;

    // Call tick handler for live stop/TP monitoring
    this.onTick?.(bid, ask, timestamp);

    if (this.currentCandle === null) {
      // First tick ever
      this.currentBucket = bucket;
      this.currentCandle = { open: mid, high: mid, low: mid, close: mid };
      return;
    }

    if (bucket !== this.currentBucket) {
      // New minute — emit completed candle
      if (this.handler) {
        const candle = this.buildCandle(this.currentBucket);
        this.handler(candle);
      }

      // Start new accumulation
      this.currentBucket = bucket;
      this.currentCandle = { open: mid, high: mid, low: mid, close: mid };
      return;
    }

    // Same minute — update OHLC
    this.currentCandle.high = Math.max(this.currentCandle.high, mid);
    this.currentCandle.low = Math.min(this.currentCandle.low, mid);
    this.currentCandle.close = mid;
  }

  private buildCandle(bucket: number): Candle {
    const c = this.currentCandle!;
    return {
      open: c.open,
      high: c.high,
      low: c.low,
      close: c.close,
      timestamp: bucket,
      timeframe: '1m',
    };
  }

  private connect(): void {
    if (this.stopped) return;

    const { cst, securityToken } = this.session.getTokens();
    const wsUrl = this.session.getWebSocketUrl();

    this.ws = new WebSocket(wsUrl);

    this.ws.onopen = () => {
      // Subscribe to quotes
      const subscribeMsg = JSON.stringify({
        destination: 'marketData.subscribe',
        correlationId: '1',
        cst,
        securityToken,
        payload: {
          epics: [this.epic],
        },
      });
      this.ws!.send(subscribeMsg);

      // Start ping
      this.startPing();
    };

    this.ws.onmessage = (event) => {
      try {
        const data = JSON.parse(String(event.data));

        if (data.destination === 'quote') {
          const payload = data.payload;
          const bid = payload?.bid;
          const ofr = payload?.ofr; // "offer" = ask
          if (typeof bid === 'number' && typeof ofr === 'number') {
            this.processTick(bid, ofr, Date.now());
          }
        }
      } catch {
        // Ignore malformed messages
      }
    };

    this.ws.onclose = () => {
      this.stopPing();
      if (!this.stopped) {
        // Reconnect after delay
        setTimeout(() => this.connect(), RECONNECT_DELAY_MS);
      }
    };

    this.ws.onerror = () => {
      // Will trigger onclose → reconnect
    };
  }

  private startPing(): void {
    this.stopPing();
    this.pingTimer = setInterval(() => {
      if (this.ws?.readyState === WebSocket.OPEN) {
        this.ws.send(JSON.stringify({ destination: 'ping' }));
      }
    }, PING_INTERVAL_MS);
  }

  private stopPing(): void {
    if (this.pingTimer) {
      clearInterval(this.pingTimer);
      this.pingTimer = null;
    }
  }

  private cleanup(): void {
    this.stopPing();
    if (this.ws) {
      this.ws.onclose = null; // Prevent reconnect
      this.ws.close();
      this.ws = null;
    }
  }
}


// FILE: apps/backend/src/providers/capital/CapitalSession.ts
export interface CapitalCredentials {
  apiKey: string;
  identifier: string;
  password: string;
  isDemo: boolean;
}

const BASE_URLS = {
  demo: 'https://demo-api-capital.backend-capital.com',
  live: 'https://api-capital.backend-capital.com',
} as const;

const WS_URL = 'wss://api-streaming-capital.backend-capital.com/connect';

const KEEPALIVE_INTERVAL_MS = 5 * 60 * 1000; // 5 minutes

/**
 * Manages a Capital.com API session.
 *
 * Handles authentication, keep-alive pings, and authenticated HTTP requests.
 * Auto re-authenticates on 401.
 */
export class CapitalSession {
  private readonly credentials: CapitalCredentials;
  private readonly baseUrl: string;
  private cst: string = '';
  private securityToken: string = '';
  private keepAliveTimer: ReturnType<typeof setInterval> | null = null;
  private connected: boolean = false;

  constructor(credentials: CapitalCredentials) {
    this.credentials = credentials;
    this.baseUrl = credentials.isDemo ? BASE_URLS.demo : BASE_URLS.live;
  }

  async connect(): Promise<void> {
    await this.authenticate();
    this.startKeepAlive();
    this.connected = true;
  }

  async destroy(): Promise<void> {
    this.stopKeepAlive();
    if (this.connected && this.cst) {
      try {
        await this.request('DELETE', '/api/v1/session');
      } catch {
        // Best-effort cleanup
      }
    }
    this.cst = '';
    this.securityToken = '';
    this.connected = false;
  }

  getTokens(): { cst: string; securityToken: string } {
    return { cst: this.cst, securityToken: this.securityToken };
  }

  getWebSocketUrl(): string {
    return WS_URL;
  }

  async get<T = unknown>(path: string): Promise<T> {
    return this.authenticatedRequest<T>('GET', path);
  }

  async post<T = unknown>(path: string, body?: unknown): Promise<T> {
    return this.authenticatedRequest<T>('POST', path, body);
  }

  async put<T = unknown>(path: string, body?: unknown): Promise<T> {
    return this.authenticatedRequest<T>('PUT', path, body);
  }

  async delete<T = unknown>(path: string): Promise<T> {
    return this.authenticatedRequest<T>('DELETE', path);
  }

  /**
   * Set account leverage for a given instrument category (e.g. INDICES).
   * Calls PUT /api/v1/accounts/preferences.
   */
  async setLeverage(category: string, leverage: number): Promise<void> {
    await this.put('/api/v1/accounts/preferences', {
      leverages: { [category]: leverage },
    });
  }

  private async authenticatedRequest<T>(method: string, path: string, body?: unknown): Promise<T> {
    const response = await this.request(method, path, body);

    if (response.status === 401) {
      // Session expired — re-authenticate and retry once
      await this.authenticate();
      const retry = await this.request(method, path, body);
      if (!retry.ok) {
        const text = await retry.text();
        throw new Error(`Capital.com API error ${retry.status}: ${text}`);
      }
      return retry.json() as Promise<T>;
    }

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`Capital.com API error ${response.status}: ${text}`);
    }

    // DELETE responses may have empty body
    const text = await response.text();
    if (!text) return {} as T;
    return JSON.parse(text) as T;
  }

  private async request(method: string, path: string, body?: unknown): Promise<Response> {
    const headers: Record<string, string> = {
      'X-CAP-API-KEY': this.credentials.apiKey,
      'Content-Type': 'application/json',
    };

    if (this.cst) {
      headers['CST'] = this.cst;
      headers['X-SECURITY-TOKEN'] = this.securityToken;
    }

    return fetch(`${this.baseUrl}${path}`, {
      method,
      headers,
      body: body ? JSON.stringify(body) : undefined,
    });
  }

  private async authenticate(): Promise<void> {
    const response = await fetch(`${this.baseUrl}/api/v1/session`, {
      method: 'POST',
      headers: {
        'X-CAP-API-KEY': this.credentials.apiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        identifier: this.credentials.identifier,
        password: this.credentials.password,
      }),
    });

    if (!response.ok) {
      const text = await response.text();
      throw new Error(`Capital.com auth failed (${response.status}): ${text}`);
    }

    const cst = response.headers.get('CST');
    const securityToken = response.headers.get('X-SECURITY-TOKEN');

    if (!cst || !securityToken) {
      throw new Error('Capital.com auth response missing CST or X-SECURITY-TOKEN headers');
    }

    this.cst = cst;
    this.securityToken = securityToken;
  }

  private startKeepAlive(): void {
    this.stopKeepAlive();
    this.keepAliveTimer = setInterval(async () => {
      try {
        await this.request('PUT', '/api/v1/session');
      } catch {
        // Keep-alive failure is non-fatal; next request will re-auth on 401
      }
    }, KEEPALIVE_INTERVAL_MS);
  }

  private stopKeepAlive(): void {
    if (this.keepAliveTimer) {
      clearInterval(this.keepAliveTimer);
      this.keepAliveTimer = null;
    }
  }
}


